"""Build correlation strategies from an error LogLine."""

from __future__ import annotations

from backtrace_agent.log_source.correlation import (
    CorrelationConfidence,
    CorrelationMethod,
    CorrelationStrategy,
    extract_log_stream_name,
)
from backtrace_agent.log_source.models import LogLine


def build_correlation_strategies(error_line: LogLine) -> list[CorrelationStrategy]:
    """Return ordered correlation strategies from most to least specific."""
    strategies: list[CorrelationStrategy] = []

    if error_line.request_id:
        strategies.append(
            CorrelationStrategy(
                method=CorrelationMethod.REQUEST_ID,
                confidence=CorrelationConfidence.EXACT_REQUEST_ID,
                request_id=error_line.request_id,
            )
        )

    if error_line.trace_id:
        strategies.append(
            CorrelationStrategy(
                method=CorrelationMethod.TRACE_ID,
                confidence=CorrelationConfidence.TRACE_CORRELATED,
                trace_id=error_line.trace_id,
            )
        )

    if error_line.session_id:
        strategies.append(
            CorrelationStrategy(
                method=CorrelationMethod.SESSION_ID,
                confidence=CorrelationConfidence.TRACE_CORRELATED,
                session_id=error_line.session_id,
            )
        )

    if error_line.span_id and error_line.endpoint:
        strategies.append(
            CorrelationStrategy(
                method=CorrelationMethod.SPAN_ID_ENDPOINT,
                confidence=CorrelationConfidence.PARTIAL,
                span_id=error_line.span_id,
                endpoint=error_line.endpoint,
            )
        )

    if error_line.endpoint and error_line.service:
        strategies.append(
            CorrelationStrategy(
                method=CorrelationMethod.ENDPOINT_SERVICE,
                confidence=CorrelationConfidence.REQUEST_SHAPE_MATCH,
                endpoint=error_line.endpoint,
                service=error_line.service,
            )
        )

    host_dims = (
        error_line.host,
        error_line.pod_name,
        error_line.container_id,
    )
    if any(host_dims):
        strategies.append(
            CorrelationStrategy(
                method=CorrelationMethod.HOST_POD_CONTAINER,
                confidence=CorrelationConfidence.PARTIAL,
                host=error_line.host,
                pod_name=error_line.pod_name,
                container_id=error_line.container_id,
            )
        )

    log_stream_name = extract_log_stream_name(error_line.raw)
    if log_stream_name:
        strategies.append(
            CorrelationStrategy(
                method=CorrelationMethod.LOG_STREAM,
                confidence=CorrelationConfidence.STREAM_FALLBACK,
                log_stream_name=log_stream_name,
            )
        )

    return strategies

